        device_model: None,
        device_type: None,
        token: "456".to_string(),
    };

    let (stop_tx, stop_rx) = oneshot::channel::<()>();

    http::server::start_with_port(
        53317,
        Some(TlsConfig {
            cert: CERT.to_string(),
            private_key: PRIVATE_KEY.to_string(),
