const BASE_64_ENGINE: GeneralPurpose = URL_SAFE_NO_PAD;

pub(crate) fn decode(data: &str) -> Result<Vec<u8>, DecodeError> {
    BASE_64_ENGINE.decode(data)
}

use std::net::IpAddr;

pub(crate) fn get_ip_group(ip: IpAddr) -> String {
    match ip {
        IpAddr::V4(ip) => {
            // IPv4: Each IP address is already a group.
            ip.to_string()
        }
        IpAddr::V6(ip) => {
            // IPv6: We treat /64 as a group.
            let segments = ip.segments();
            format!(
                "{:x}:{:x}:{:x}:{:x}",
                segments[0], segments[1], segments[2], segments[3]
            )
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::str::FromStr;

    #[test]
    fn test_get_ip_group() {
        assert_eq!(
            get_ip_group(IpAddr::from_str("1.2.3.4").unwrap()),
            "1.2.3.4"
        );
        assert_eq!(
            get_ip_group(IpAddr::from_str("1:2:3:4:5:6:7:8").unwrap()),
            "1:2:3:4"
        );
        assert_eq!(
            get_ip_group(IpAddr::from_str("a:b:c:d:e:f:0:1").unwrap()),
            "a:b:c:d"
        );
    }
}

use axum::http::StatusCode;
use axum::response::{IntoResponse, Response};

// https://github.com/tokio-rs/axum/blob/main/examples/oauth/src/main.rs

#[derive(Debug)]
pub struct AppError {
    status: StatusCode,
    message: Option<String>,
    error: Option<anyhow::Error>,
}

impl AppError {
    pub fn status(status: StatusCode, message: Option<String>) -> Self {
        Self {
            status,
            message,
            error: None,
        }
    }
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        if self.status >= StatusCode::INTERNAL_SERVER_ERROR {
            tracing::error!(
                "{:?}; {:?}",
                match &self.message {
                    Some(message) => message,
                    None => "(no message)",
                },
                match &self.error {
                    Some(error) => error.to_string(),
                    None => "(no error)".to_string(),
                }
            );
        }

        // return status code with message
        if let Some(message) = self.message {
            (self.status, message).into_response()
        } else {
            self.status.into_response()
        }
    }
}

impl<E> From<E> for AppError
where
    E: Into<anyhow::Error>,
{
    fn from(err: E) -> Self {
        Self {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            message: None,
            error: Some(err.into()),
        }
    }
}

